import { EyeIcon, EyeSlashIcon } from "@heroicons/react/20/solid";
import React, { useState } from "react";

type TInputField = {
  type: string;
  name: string;
  placeholder?: string;
  value: string | number;
  label?: string;
  onChange: React.ChangeEventHandler<HTMLInputElement>;
  err?: string;
  disabled?: boolean;
  variants?: "medium" | "small";
};

export const InputField = ({
  type,
  name,
  placeholder,
  value,
  label,
  onChange,
  err = "",
  disabled = false,
  variants = "medium",
}: TInputField) => {
  const [showPassword, setShowPassword] = useState(false);
  const innerType = showPassword ? "text" : "password";
  return (
    <label className="form-control w-full max-w-full relative">
      <div className="label">
        <span className="label-text">{label}</span>
      </div>
      <input
        type={type === "password" ? innerType : type}
        name={name}
        placeholder={placeholder}
        className={`text-black input input-bordered w-full max-w-full ${
          variants === "medium" ? "input-md" : "input-sm"
        } ${err != "" ? "input-error" : ""}`}
        onChange={onChange}
        value={value}
        disabled={disabled}
      />
      <button
        type="button"
        className={`absolute w-5 h-5 right-4 top-[50px] ${
          type !== "password" ? "hidden" : ""
        }`}
        onClick={() => {
          setShowPassword(!showPassword);
        }}
      >
        {showPassword ? (
          <EyeIcon className="text-gray-500" />
        ) : (
          <EyeSlashIcon className="text-gray-500" />
        )}
      </button>
      <div className="label absolute -bottom-7">
        <span className="label-text-alt text-red-500">{err}</span>
      </div>
    </label>
  );
};
